{"version":3,"file":"main.css","mappings":"AAqIA,0BACE,UAAW,CACX,gBAAiB,CACjB,YAAa,CACb,qBAAsB,CACtB,sEAA0E,CAC1E,aACF,CACA,iCACE,eAAgB,CAChB,aACF,CACA,iCACE,iBAAkB,CAClB,eAAgB,CAChB,eAAgB,CAChB,iBAAkB,CAClB,qBACF,CACA,oCACE,eAAgB,CAChB,mBAAoB,CACpB,eAAgB,CAChB,aAAc,CACd,eACF,CACA,gCACE,YAAa,CACb,qBAAsB,CACtB,QACF,CACA,iCACE,YAAa,CACb,qBAAsB,CACtB,WACF,CACA,iCACE,kBAAmB,CACnB,eAAgB,CAChB,YACF,CACA,qEAEE,UAAW,CACX,qBAAsB,CACtB,kBAAmB,CACnB,aAAc,CACd,6BAAiC,CACjC,sCAA0C,CAC1C,iBAAkB,CAClB,qBACF,CACA,oCACE,eAAgB,CAChB,eACF,CACA,+FAEE,aAAc,CACd,WACF,CACA,uCACE,YAAa,CACb,QAAS,CACT,cACF,CACA,iCACE,mBAAoB,CACpB,kBAAmB,CACnB,UAAW,CACX,kBAAmB,CACnB,cACF,CACA,uCACE,oBACF,CACA,gCACE,iBAAkB,CAClB,YAAa,CACb,QAAS,CACT,iBACF,CACA,wCACE,kBACF,CACA,kCACE,iBAAkB,CAClB,mBAAoB,CACpB,mBAAoB,CACpB,eAAgB,CAChB,aAAc,CACd,0DAA6D,CAC7D,WAAY,CACZ,iBAAkB,CAClB,cACF,CACA,uDACE,0DACF,CACA,2CACE,WAAY,CACZ,kBACF,CACA,mCACE,kBAAmB,CACnB,+BAAgC,CAChC,iBAAkB,CAClB,8BAAkC,CAClC,sCACF,CACA,yCACE,iBAAkB,CAClB,eAAgB,CAChB,qBAAsB,CACtB,aACF,CACA,wCACE,QAAS,CACT,iBAAkB,CAClB,eAAgB,CAChB,oBAAqB,CACrB,qBAAsB,CACtB,eAAgB,CAChB,eACF","sources":["src://tavern_helper_template/src/开场白/Opening.vue"],"sourcesContent":["<template>\n  <div class=\"opening\">\n    <div class=\"opening__inner\">\n      <h1 class=\"opening__title\">《异世界穿越APP》</h1>\n\n      <form class=\"opening__form\" @submit.prevent=\"onSubmit\">\n        <div class=\"opening__field\">\n          <label class=\"opening__label\">目标世界</label>\n          <input\n            v-model.trim=\"form.targetWorld\"\n            type=\"text\"\n            class=\"opening__input\"\n            placeholder=\"例如：XX世界 / 某部作品名\"\n          />\n        </div>\n\n        <div class=\"opening__field\">\n          <label class=\"opening__label\">穿越方式</label>\n          <div class=\"opening__radio-group\">\n            <label class=\"opening__radio\">\n              <input v-model=\"form.crossType\" type=\"radio\" value=\"肉身穿越\" />\n              <span>肉身穿越</span>\n            </label>\n            <label class=\"opening__radio\">\n              <input v-model=\"form.crossType\" type=\"radio\" value=\"替换穿越\" />\n              <span>替换穿越</span>\n            </label>\n          </div>\n        </div>\n\n        <div class=\"opening__field\">\n          <label class=\"opening__label\">主角设定</label>\n          <textarea\n            v-model.trim=\"form.protagonist\"\n            class=\"opening__textarea\"\n            rows=\"3\"\n            placeholder=\"一句话概括主角人设\"\n          />\n        </div>\n\n        <button\n          type=\"submit\"\n          class=\"opening__submit\"\n          :disabled=\"!canSubmit || sending\"\n        >\n          {{ sending ? '正在向 AI 发送开场白…' : '开始穿越' }}\n        </button>\n\n        <p v-if=\"hasSubmittedOnce\" class=\"opening__hint opening__hint--bottom\">\n          已发送开场白，可直接继续对话。\n        </p>\n      </form>\n\n      <div v-if=\"canSubmit\" class=\"opening__preview\">\n        <div class=\"opening__preview-title\">将发送给 AI 的开场白指令预览</div>\n        <pre class=\"opening__preview-body\">{{ preview }}</pre>\n      </div>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\n// 不显式 import vue：tsconfig 的 types 白名单会导致在 .vue 中解析不到 'vue' 模块；\n// 构建时 unplugin-auto-import 会注入 reactive/computed，auto-imports.d.ts 也声明了全局。\nconst form = reactive({\n  targetWorld: '',\n  crossType: '' as '' | '肉身穿越' | '替换穿越',\n  protagonist: '',\n});\n\nconst sending = ref(false);\nconst hasSubmittedOnce = ref(false);\n\nconst canSubmit = computed(() => {\n  return (\n    form.targetWorld.length > 0 &&\n    (form.crossType === '肉身穿越' || form.crossType === '替换穿越') &&\n    form.protagonist.length > 0\n  );\n});\n\nconst preview = computed(() => buildMessage());\n\nfunction buildMessage(): string {\n  const lines = [\n    '生成开场白：',\n    '说明：肉身穿越 = 以外来人的身份直接穿越到异世界；替换穿越 = 获得一个已存在的异世界身份开局。',\n    `目标世界：${form.targetWorld}`,\n    `穿越方式：${form.crossType}`,\n    `主角设定：${form.protagonist}`,\n  ];\n  return lines.join('\\n');\n}\n\nasync function onSubmit() {\n  if (!canSubmit.value || sending.value) return;\n  const message = buildMessage();\n  sending.value = true;\n  try {\n    // 在当前聊天中追加一条用户消息，但不触发生成，让玩家手动点“重新生成”\n    SillyTavern.addOneMessage(\n      {\n        name: SillyTavern.name1,\n        is_user: true,\n        is_system: false,\n        mes: message,\n      },\n      { scroll: true },\n    );\n    hasSubmittedOnce.value = true;\n    console.info('开场白消息已插入聊天', { message });\n    try {\n      // 使用酒馆内置 toastr，如果可用的话\n      // eslint-disable-next-line @typescript-eslint/no-explicit-any\n      (window as any).toastr?.success?.('已插入开场白消息，可在聊天中点“重新生成”开始。');\n    } catch {\n      // ignore\n    }\n  } catch (e) {\n    console.error('开场白消息插入失败', e);\n    try {\n      // eslint-disable-next-line @typescript-eslint/no-explicit-any\n      (window as any).toastr?.error?.('开场白消息插入失败，请稍后重试。');\n    } catch {\n      // ignore\n    }\n  } finally {\n    sending.value = false;\n  }\n}\n</script>\n\n<style scoped>\n.opening {\n  width: 100%;\n  min-height: 280px;\n  padding: 1rem;\n  box-sizing: border-box;\n  background: linear-gradient(135deg, #1e1b4b 0%, #312e81 50%, #1e1b4b 100%);\n  color: #e0e7ff;\n}\n.opening__inner {\n  max-width: 24rem;\n  margin: 0 auto;\n}\n.opening__title {\n  font-size: 1.25rem;\n  font-weight: 700;\n  margin: 0 0 1rem;\n  text-align: center;\n  letter-spacing: 0.05em;\n}\n.opening__subtitle {\n  margin: 0 0 1rem;\n  font-size: 0.8125rem;\n  line-height: 1.4;\n  color: #c7d2fe;\n  text-align: left;\n}\n.opening__form {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n.opening__field {\n  display: flex;\n  flex-direction: column;\n  gap: 0.35rem;\n}\n.opening__label {\n  font-size: 0.875rem;\n  font-weight: 600;\n  opacity: 0.95;\n}\n.opening__input,\n.opening__textarea {\n  width: 100%;\n  padding: 0.5rem 0.6rem;\n  font-size: 0.875rem;\n  color: #e5e7eb;\n  background: rgba(15, 23, 42, 0.9);\n  border: 1px solid rgba(129, 140, 248, 0.6);\n  border-radius: 6px;\n  box-sizing: border-box;\n}\n.opening__textarea {\n  resize: vertical;\n  min-height: 4rem;\n}\n.opening__input::placeholder,\n.opening__textarea::placeholder {\n  color: #9ca3af;\n  opacity: 0.9;\n}\n.opening__radio-group {\n  display: flex;\n  gap: 1rem;\n  flex-wrap: wrap;\n}\n.opening__radio {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.4rem;\n  font-size: 0.875rem;\n  cursor: pointer;\n}\n.opening__radio input {\n  accent-color: #818cf8;\n}\n.opening__hint {\n  font-size: 0.75rem;\n  opacity: 0.85;\n  margin: 0;\n  padding: 0.25rem 0;\n}\n.opening__hint--bottom {\n  margin-top: 0.25rem;\n}\n.opening__submit {\n  margin-top: 0.5rem;\n  padding: 0.6rem 1rem;\n  font-size: 0.9375rem;\n  font-weight: 600;\n  color: #1e1b4b;\n  background: linear-gradient(180deg, #a5b4fc 0%, #818cf8 100%);\n  border: none;\n  border-radius: 8px;\n  cursor: pointer;\n}\n.opening__submit:hover:not(:disabled) {\n  background: linear-gradient(180deg, #c7d2fe 0%, #a5b4fc 100%);\n}\n.opening__submit:disabled {\n  opacity: 0.5;\n  cursor: not-allowed;\n}\n.opening__preview {\n  margin-top: 1.25rem;\n  padding: 0.75rem 0.75rem 0.65rem;\n  border-radius: 8px;\n  background: rgba(15, 23, 42, 0.85);\n  border: 1px solid rgba(129, 140, 248, 0.6);\n}\n.opening__preview-title {\n  font-size: 0.75rem;\n  font-weight: 600;\n  margin-bottom: 0.35rem;\n  color: #c7d2fe;\n}\n.opening__preview-body {\n  margin: 0;\n  font-size: 0.75rem;\n  line-height: 1.4;\n  white-space: pre-wrap;\n  word-break: break-word;\n  max-height: 8rem;\n  overflow-y: auto;\n}\n</style>\n"],"names":[],"sourceRoot":""}
