bel class=\"opening__label\">主角设定</label>\n          <textarea\n            v-model.trim=\"form.protagonist\"\n            class=\"opening__textarea\"\n            rows=\"3\"\n            placeholder=\"简要写出主角人设；若为替换穿越，请写清楚扮演的身份\"\n          />\n        </div>\n\n        <button type=\"submit\" class=\"opening__submit\" :disabled=\"!canSubmit\">开始穿越</button>\n      </form>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\n// 不显式 import vue：tsconfig 的 types 白名单会导致在 .vue 中解析不到 'vue' 模块；\n// 构建时 unplugin-auto-import 会注入 reactive/computed，auto-imports.d.ts 也声明了全局。\nconst form = reactive({\n  targetWorld: '',\n  crossType: '' as '' | '肉身穿越' | '替换穿越',\n  protagonist: '',\n});\n\nconst canSubmit = computed(() => {\n  return (\n    form.targetWorld.length > 0 &&\n    (form.crossType === '肉身穿越' || form.crossType === '替换穿越') &&\n    form.protagonist.length > 0\n  );\n});\n\nfunction buildMessage(): string {\n  const lines = [\n    '生成开场白：',\n    '说明：肉身穿越 = 以外来人的身份直接穿越到异世界；替换穿越 = 获得一个已存在的异世界身份开局。',\n    `目标世界：${form.targetWorld}`,\n    `穿越方式：${form.crossType}`,\n    `主角设定：${form.protagonist}`,\n  ];\n  return lines.join('\\n');\n}\n\nasync function onSubmit() {\n  if (!canSubmit.value) return;\n  const message = buildMessage();\n  try {\n    await generate({ user_input: message });\n  } catch (e) {\n    console.error('开场白发送失败', e);\n  }\n}\n</script>\n\n<style scoped>\n.opening {\n  width: 100%;\n  min-height: 280px;\n  padding: 1rem;\n  box-sizing: border-box;\n  background: linear-gradient(135deg, #1e1b4b 0%, #312e81 50%, #1e1b4b 100%);\n  color: #e0e7ff;\n}\n.opening__inner {\n  max-width: 24rem;\n  margin: 0 auto;\n}\n.opening__title {\n  font-size: 1.25rem;\n  font-weight: 700;\n  margin: 0 0 1rem;\n  text-align: center;\n  letter-spacing: 0.05em;\n}\n.opening__form {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n.opening__field {\n  display: flex;\n  flex-direction: column;\n  gap: 0.35rem;\n}\n.opening__label {\n  font-size: 0.875rem;\n  